)

const graphqlWSSubprotocol = "graphql-transport-ws"

const changeEventsSubscription = `subscription ChangeEvents($projectID: ID!) { changeEvents(projectID: $projectID) { ...ChangeEventFields } }`

// ChangeEvent mirrors the GraphQL subscription payload for lifecycle updates.
type ChangeEvent struct {
	EventID   string    `json:"eventID"`
	BeadID    string    `json:"beadID"`
	Kind      string    `json:"kind"`
	Summary   string    `json:"summary"`
	Body      string    `json:"body"`
	Actor     string    `json:"actor"`
	Timestamp time.Time `json:"timestamp"`
}

// ChangeEventFromLifecycle converts the local bead lifecycle event into the
// Axon GraphQL subscription shape.
func ChangeEventFromLifecycle(src bead.LifecycleEvent) ChangeEvent {
	return ChangeEvent{
		EventID:   src.EventID,
		BeadID:    src.BeadID,
		Kind:      src.Kind,
		Summary:   src.Summary,
		Body:      src.Body,
		Actor:     src.Actor,
		Timestamp: src.Timestamp,
	}
}

// ToLifecycleEvent converts the GraphQL subscription payload back into the
// local bead lifecycle model.
func (c ChangeEvent) ToLifecycleEvent() bead.LifecycleEvent {
	return bead.LifecycleEvent{
		EventID:   c.EventID,
		BeadID:    c.BeadID,
		Kind:      c.Kind,
		Summary:   c.Summary,
		Body:      c.Body,
		Actor:     c.Actor,
		Timestamp: c.Timestamp,
	}
}

// SubscriptionTransport is the minimal GraphQL-over-WebSocket transport used
// by the Axon client subscription path.
type SubscriptionTransport interface {
	Subscribe(ctx context.Context, query string, variables map[string]any) (<-chan json.RawMessage, error)
}

// DualTransport lets callers combine a query transport and a subscription
// transport behind the same Client value.
type DualTransport struct {
	Queries       Transport
	Subscriptions SubscriptionTransport
}

// Query forwards GraphQL queries and mutations to the query transport.
func (d DualTransport) Query(ctx context.Context, query string, variables map[string]any, response any) error {
	if d.Queries == nil {
		return fmt.Errorf("axon: query transport not configured")
	}
	return d.Queries.Query(ctx, query, variables, response)
}

// Subscribe forwards GraphQL subscriptions to the subscription transport.
func (d DualTransport) Subscribe(ctx context.Context, query string, variables map[string]any) (<-chan json.RawMessage, error) {
	if d.Subscriptions == nil {
		return nil, fmt.Errorf("axon: subscription transport not configured")
	}
	return d.Subscriptions.Subscribe(ctx, query, variables)
}

// WebSocketSubscriptionTransport speaks the graphql-transport-ws protocol.
type WebSocketSubscriptionTransport struct {
	URL         string
	Header      http.Header
	Dialer      *websocket.Dialer
	InitPayload map[string]any
}

// NewWebSocketSubscriptionTransport creates a websocket subscription transport
// rooted at url. The URL may be ws://, wss://, http://, or https://.
func NewWebSocketSubscriptionTransport(url string) *WebSocketSubscriptionTransport {
	return &WebSocketSubscriptionTransport{URL: url}
}

// Query is unsupported on the websocket subscription transport.
func (t *WebSocketSubscriptionTransport) Query(context.Context, string, map[string]any, any) error {
	return fmt.Errorf("axon: websocket subscription transport does not execute queries")
}

// Subscribe opens a GraphQL WebSocket subscription and streams raw payloads
// from graphql-transport-ws next messages.
func (t *WebSocketSubscriptionTransport) Subscribe(ctx context.Context, query string, variables map[string]any) (<-chan json.RawMessage, error) {
	url := normalizeWebSocketURL(strings.TrimSpace(t.URL))
	if url == "" {
		return nil, fmt.Errorf("axon: websocket subscription url is required")
	}

	dialer := websocket.DefaultDialer
	if t.Dialer != nil {
		dialer = t.Dialer
	}
	if len(dialer.Subprotocols) == 0 {
		dialer = cloneDialer(dialer)
		dialer.Subprotocols = []string{graphqlWSSubprotocol}
	}

	header := cloneHeader(t.Header)
	conn, _, err := dialer.DialContext(ctx, url, header)
	if err != nil {
		return nil, fmt.Errorf("axon: websocket dial: %w", err)
	}

	closed := make(chan struct{})
	var closeOnce sync.Once
	cleanup := func() {
		closeOnce.Do(func() {
			close(closed)
			_ = conn.Close()
		})
	}
	go func() {
		select {
		case <-ctx.Done():
			cleanup()
		case <-closed:
		}
	}()

	if conn.Subprotocol() != "" && conn.Subprotocol() != graphqlWSSubprotocol {
		cleanup()
		return nil, fmt.Errorf("axon: websocket subprotocol mismatch: got %q want %q", conn.Subprotocol(), graphqlWSSubprotocol)
	}

	if err := conn.WriteJSON(graphqlWSMessage{Type: "connection_init", Payload: mustJSON(t.InitPayload)}); err != nil {
		cleanup()
		return nil, fmt.Errorf("axon: websocket connection_init: %w", err)
	}

	for {
		var msg graphqlWSMessage
		if err := conn.ReadJSON(&msg); err != nil {
			cleanup()
			return nil, fmt.Errorf("axon: websocket ack: %w", err)
		}
		switch msg.Type {
		case "connection_ack":
			goto subscribed
		case "ping":
			_ = conn.WriteJSON(graphqlWSMessage{Type: "pong"})
		case "error":
			cleanup()
			return nil, fmt.Errorf("axon: websocket connection error")
		}
	}

subscribed:
	subPayload, err := json.Marshal(map[string]any{
		"query":     query,
		"variables": variables,
	})
	if err != nil {
		cleanup()
		return nil, fmt.Errorf("axon: websocket subscribe payload: %w", err)
	}
	if err := conn.WriteJSON(graphqlWSMessage{ID: "1", Type: "subscribe", Payload: subPayload}); err != nil {
		cleanup()
		return nil, fmt.Errorf("axon: websocket subscribe: %w", err)
	}

	out := make(chan json.RawMessage)
	go func() {
		defer close(out)
		defer cleanup()
		for {
			var msg graphqlWSMessage
			if err := conn.ReadJSON(&msg); err != nil {
				return
			}
			switch msg.Type {
			case "next":
				if len(msg.Payload) == 0 {
					continue
				}
				payload := append(json.RawMessage(nil), msg.Payload...)
				select {
				case out <- payload:
				case <-ctx.Done():
					return
				}
			case "complete":
				return
			case "ping":
				_ = conn.WriteJSON(graphqlWSMessage{Type: "pong"})
			case "error":
				return
			}
		}
	}()

	return out, nil
}

type graphqlWSMessage struct {
	ID      string          `json:"id,omitempty"`
	Type    string          `json:"type"`
	Payload json.RawMessage `json:"payload,omitempty"`
}

type changeEventsEnvelope struct {
	Data struct {
		ChangeEvents *ChangeEvent `json:"changeEvents,omitempty"`
	} `json:"data"`
}

func normalizeWebSocketURL(url string) string {
	switch {
	case strings.HasPrefix(url, "http://"):
		return "ws://" + strings.TrimPrefix(url, "http://")
	case strings.HasPrefix(url, "https://"):
		return "wss://" + strings.TrimPrefix(url, "https://")
	default:
		return url
	}

The current `cli/internal/bead/backend.go` interface is too coarse for
Axon — `WriteAll(beads []Bead)` cannot reasonably be implemented
against a remote entity store, and `WithLock` assumes a process-local
mutex around an in-memory rewrite. This TD replaces the existing
interface with a per-entity surface that both backends can satisfy.
Existing JSONL semantics are preserved by a thin adapter that wraps
the existing `ReadAll`/`WriteAll`/`flock` pair.

```go
// cli/internal/bead/backend.go
package bead

import "context"

// Backend is the storage contract for the bead tracker. Both the
// JSONL backend (cli/internal/bead/backend_jsonl.go) and the axon
// backend (cli/internal/bead/axon/) implement this surface. The
// chaos tests under cli/internal/bead/ run against any registered
// Backend via newTestStore(t, BackendName).
type Backend interface {
    // Init prepares storage (create JSONL file + lock dir; or for
    // axon: ensure collections exist and registered schema is current).
    Init(ctx context.Context) error

    // Get returns one bead with its OCC version. ErrNotFound for missing.
    Get(ctx context.Context, id string) (Bead, Version, error)

    // List returns all beads in the tracker collection (open + in_progress
    // + closed not yet archived). Order is unspecified.
    List(ctx context.Context) ([]Bead, error)

    // Create persists a new bead. Bead.ID may be empty; backend assigns
    // a ddx-<8hex> id and returns the assigned id. Fails if id is set
    // and already exists.
    Create(ctx context.Context, b Bead) (string, Version, error)

    // Update applies mutate to the bead identified by id under
    // optimistic concurrency control: read at version V, apply mutate,
    // write iff stored version == V. ErrVersionMismatch on conflict;
    // caller retries. Used by claim, status transitions, and any
    // field edit. Backend MUST serialize concurrent Update calls on
    // the same id (jsonl: via flock; axon: via expectedVersion).
    Update(ctx context.Context, id string, mutate func(*Bead) error) error

    // AppendEvent records an immutable audit event linked to a bead.
    // For jsonl: appends to the inline events array under the same
    // lock as the bead row. For axon: createEntity in
    // ddx_bead_events + createLink(event_of) in one commitTransaction.
    AppendEvent(ctx context.Context, beadID string, ev Event) error

    // AddDep / RemoveDep maintain the depends_on graph. For jsonl:
    // mutate Dependencies on the bead row. For axon: createLink /
    // deleteLink with type=depends_on.
    AddDep(ctx context.Context, fromID, toID string) error
    RemoveDep(ctx context.Context, fromID, toID string) error

    // Ready returns beads with Status==open whose every dependency
    // is Status==closed. Implementations are free to compute this
    // server-side; the JSONL implementation does it client-side; the
    // axon implementation uses the v1 two-phase GraphQL path until
    // axon-05c1019d ships an isReady computed field.
    Ready(ctx context.Context) ([]Bead, error)

    // Close is sugar for Update(id, b -> b.Status = closed) plus
    // AppendEvent(closed). Provided so the backend can fuse both
    // writes into a single transaction (axon) or single locked
    // rewrite (jsonl).
    Close(ctx context.Context, id string) error

    // Export streams beads in bd/br JSONL interchange shape (events
    // materialised inline). Round-trip with Import is verified by
    // schema_compat_test.go.
    Export(ctx context.Context, w BeadWriter) error
    Import(ctx context.Context, r BeadReader) error
}

// Version is an opaque OCC token (jsonl: monotonic int from the
// in-memory snapshot; axon: GraphQL Entity.version).
type Version uint64

var (
    ErrNotFound        = errors.New("bead: not found")
    ErrVersionMismatch = errors.New("bead: version mismatch (concurrent update)")
    ErrBackendOffline  = errors.New("bead: backend unreachable")
)
```

